        case 1:
            return .rectangle(width: reader.readF64(), height: reader.readF64())
        case 2:
            return .triangle(a: Point.decode(from: &reader), b: Point.decode(from: &reader), c: Point.decode(from: &reader))
        case 3:
            return .point
        default:
            fatalError("Invalid Shape tag: \(tag)")
        }
    }

    @inlinable func encode(to writer: inout WireWriter) {
        switch self {
        case let .circle(radius):
            writer.writeI32(0)
            writer.writeF64(radius)
        case let .rectangle(width, height):
            writer.writeI32(1)
            writer.writeF64(width)
            writer.writeF64(height)
        case let .triangle(a, b, c):
            writer.writeI32(2)
            a.encode(to: &writer)
            b.encode(to: &writer)
            c.encode(to: &writer)
        case .point:
            writer.writeI32(3)
        }
    }
}

extension Shape {

    public init(radius: Double) {
        let buf = boltffi_shape_new(radius)

        defer { boltffi_free_buf(buf) }
        self = boltffiDecodeOwnedBuf(buf.ptr, Int(buf.len)) { reader in
            Shape.decode(from: &reader)
        }
    }

