        let buf = boltffi_shape_square(side)

        defer { boltffi_free_buf(buf) }
        self = boltffiDecodeOwnedBuf(buf.ptr, Int(buf.len)) { reader in
            Shape.decode(from: &reader)
        }
    }

    public init(tryCircle radius: Double) throws {
        let buf = boltffi_shape_try_circle(radius)

        defer { boltffi_free_buf(buf) }
        self = try boltffiDecodeOwnedBuf(buf.ptr, Int(buf.len)) { reader in
            try reader.readResultOrThrow(ok: { reader in Shape.decode(from: &reader) }, err: { reader in FfiError(message: reader.readString()) })
        }
    }

    public func area() -> Double {
        let selfBytes = boltffiEncode { writer in self.encode(to: &writer) }
        return boltffi_shape_area(selfBytes, UInt(selfBytes.count))
    }

    public func describe() -> String {
        let selfBytes = boltffiEncode { writer in self.encode(to: &writer) }
        let buf = boltffi_shape_describe(selfBytes, UInt(selfBytes.count))
        defer { boltffi_free_buf(buf) }
        return boltffiDecodeOwnedBuf(buf.ptr, Int(buf.len)) { reader in reader.readString() }
    }

    public static func variantCount() -> UInt32 {
        return boltffi_shape_variant_count()
    }
}

