public func echoVecI32(v: [Int32]) -> [Int32] {
    return v.withUnsafeBufferPointer { vPtr in
        let buf = boltffi_echo_vec_i32(vPtr.baseAddress, UInt(vPtr.count))
        defer { boltffi_free_buf(buf) }
        guard buf.len > 0, let ptr = buf.ptr else { return [] }
        let count = Int(buf.len) / MemoryLayout<Int32>.stride
        let rawPtr = UnsafeRawPointer(ptr).assumingMemoryBound(to: Int32.self)
        return Array(UnsafeBufferPointer(start: rawPtr, count: count))
    }
}

