/// Publishes events to subscribers. Clients call `subscribe_values`
/// or `subscribe_points` to get a stream, then poll for new items.
public final class EventBus {
    let handle: OpaquePointer

    init(handle: OpaquePointer) {
        self.handle = handle
    }

    public init() {
        let ptr = boltffi_event_bus_new()!
        self.handle = ptr
    }

    deinit {
        boltffi_event_bus_free(handle)
    }

    public func emitValue(value: Int32) {
        boltffi_event_bus_emit_value(handle, value)
    }

    public func emitPoint(point: Point) {
        boltffi_event_bus_emit_point(handle, ___Point(x: point.x, y: point.y))
    }

    public func emitBatch(values: [Int32]) -> UInt32 {
        return values.withUnsafeBufferPointer { valuesPtr in
            return boltffi_event_bus_emit_batch(handle, valuesPtr.baseAddress, UInt(valuesPtr.count))
        }
    }

    public func subscribeValues() -> _Concurrency.AsyncStream<Int32> {
        _Concurrency.AsyncStream<Int32>(bufferingPolicy: .unbounded) { continuation in
            guard let subscription = boltffi_event_bus_subscribe_values(self.handle) else {
                continuation.finish()
                return
            }
            let context = WireStreamContextBase(
                subscription: subscription, batchSize: 16,
                drainAvailableItems: { subscription, batchSize in
                    boltffiDrainDirectStreamBatch(
                        subscription: subscription,
                        batchSize: batchSize,
                        popBatch: boltffi_event_bus_subscribe_values_pop_batch
                    ) { rawItems in
                        for rawItem in rawItems {
                            let item = rawItem
                            _ = continuation.yield(item)
                        }
                    }
                },
                poll: boltffi_event_bus_subscribe_values_poll,
                unsubscribe: boltffi_event_bus_subscribe_values_unsubscribe,
                freeFn: boltffi_event_bus_subscribe_values_free,
                atomicCas: boltffi_atomic_u8_cas,
                finish: { continuation.finish() }
            )
            continuation.onTermination = { @Sendable _ in context.requestTermination() }
            context.start()
        }
    }
    public func subscribePoints() -> _Concurrency.AsyncStream<Point> {
        _Concurrency.AsyncStream<Point>(bufferingPolicy: .unbounded) { continuation in
            guard let subscription = boltffi_event_bus_subscribe_points(self.handle) else {
                continuation.finish()
                return
            }
            let context = WireStreamContextBase(
                subscription: subscription, batchSize: 16,
                drainAvailableItems: { subscription, batchSize in
                    boltffiDrainDirectStreamBatch(
                        subscription: subscription,
                        batchSize: batchSize,
                        popBatch: boltffi_event_bus_subscribe_points_pop_batch
                    ) { rawItems in
                        for rawItem in rawItems {
                            let item = Point(x: rawItem.x, y: rawItem.y)
                            _ = continuation.yield(item)
                        }
                    }
                },
                poll: boltffi_event_bus_subscribe_points_poll,
                unsubscribe: boltffi_event_bus_subscribe_points_unsubscribe,
                freeFn: boltffi_event_bus_subscribe_points_free,
                atomicCas: boltffi_atomic_u8_cas,
                finish: { continuation.finish() }
            )
            continuation.onTermination = { @Sendable _ in context.requestTermination() }
            context.start()
        }
    }
    public func subscribeValuesBatch() -> EventBusSubscribeValuesBatchSubscription {
        EventBusSubscribeValuesBatchSubscription(
            handle: boltffi_event_bus_subscribe_values_batch(self.handle),
            readBatch: { subscription, batchSize in
                return boltffiReadDirectStreamBatch(
                    subscription: subscription,
                    batchSize: batchSize,
                    popBatch: boltffi_event_bus_subscribe_values_batch_pop_batch
                ) { rawItems in
                    rawItems.map { rawItem in
                    rawItem
                    }
                }
            },
            wait: boltffi_event_bus_subscribe_values_batch_wait,
            unsubscribe: boltffi_event_bus_subscribe_values_batch_unsubscribe,
            freeFn: boltffi_event_bus_subscribe_values_batch_free
        )
    }
    public func subscribeValuesCallback(callback: @escaping (Int32) -> Void) -> EventBusSubscribeValuesCallbackCancellable {
        guard let subscription = boltffi_event_bus_subscribe_values_callback(self.handle) else {
            return EventBusSubscribeValuesCallbackCancellable {}
        }

        final class CallbackContext: @unchecked Sendable {
            let subscription: SubscriptionHandle
            let batchSize: UInt
            let drainAvailableItems: (SubscriptionHandle, UInt) -> Bool
            let unsubscribe: (SubscriptionHandle?) -> Void
            let freeFn: (SubscriptionHandle?) -> Void
            let atomicCas: (UnsafeMutablePointer<UInt8>?, UInt8, UInt8) -> Bool
            let callback: (Int32) -> Void
            private var lifecycleTag: UInt8 = 0
            private var callbackTag: UInt8 = 0

            init(
                subscription: SubscriptionHandle, batchSize: UInt,
                drainAvailableItems: @escaping (SubscriptionHandle, UInt) -> Bool,
                poll: @escaping (SubscriptionHandle?, UInt64, StreamContinuationCallback?) -> Void,
                unsubscribe: @escaping (SubscriptionHandle?) -> Void,
                freeFn: @escaping (SubscriptionHandle?) -> Void,
                atomicCas: @escaping (UnsafeMutablePointer<UInt8>?, UInt8, UInt8) -> Bool,
                callback: @escaping (Int32) -> Void
            ) {
                self.subscription = subscription; self.batchSize = batchSize
                self.drainAvailableItems = drainAvailableItems; self.unsubscribe = unsubscribe
                self.freeFn = freeFn; self.atomicCas = atomicCas
                self.callback = callback
            }

            func start() { registerPoll() }

            func requestTermination() {
                let started = withUnsafeMutablePointer(to: &lifecycleTag) { atomicCas($0, 0, 1) }
                if started { unsubscribe(subscription); _ = withUnsafeMutablePointer(to: &lifecycleTag) { atomicCas($0, 1, 2) } }
                attemptFinalize()
            }

            private func attemptFinalize() {
                guard (withUnsafeMutablePointer(to: &callbackTag) { atomicCas($0, 0, 0) }) else { return }
                guard (withUnsafeMutablePointer(to: &lifecycleTag) { atomicCas($0, 2, 3) }) else { return }
                freeFn(subscription)
            }

            private func schedulePoll() { _Concurrency.Task { [self] in await _Concurrency.Task.yield(); registerPoll() } }

            private func registerPoll() {
                guard (withUnsafeMutablePointer(to: &lifecycleTag) { atomicCas($0, 0, 0) }) else { attemptFinalize(); return }
                let data = UInt64(UInt(bitPattern: Unmanaged.passRetained(self).toOpaque()))
                boltffi_event_bus_subscribe_values_callback_poll(subscription, data) { data, result in
                    Unmanaged<CallbackContext>.fromOpaque(UnsafeRawPointer(bitPattern: UInt(data))!).takeRetainedValue().handlePoll(result)
                }
            }

            private func handlePoll(_ pollResult: Int8) {
                let isClosed = pollResult == StreamPollResult.closed.rawValue
                guard (withUnsafeMutablePointer(to: &callbackTag) { atomicCas($0, 0, 1) }) else { attemptFinalize(); return }
                defer { _ = withUnsafeMutablePointer(to: &callbackTag) { atomicCas($0, 1, 0) }; attemptFinalize() }
                guard (withUnsafeMutablePointer(to: &lifecycleTag) { atomicCas($0, 0, 0) }) else { return }
                while drainAvailableItems(subscription, batchSize) {}
                if isClosed { requestTermination(); return }
                guard (withUnsafeMutablePointer(to: &lifecycleTag) { atomicCas($0, 0, 0) }) else { return }
                schedulePoll()
            }
        }

        let context = CallbackContext(
            subscription: subscription, batchSize: 16,
            drainAvailableItems: { subscription, batchSize in
                boltffiDrainDirectStreamBatch(
                    subscription: subscription,
                    batchSize: batchSize,
                    popBatch: boltffi_event_bus_subscribe_values_callback_pop_batch
                ) { rawItems in
                    for rawItem in rawItems {
                        let item = rawItem
                        callback(item)
                    }
                }
            },
            poll: boltffi_event_bus_subscribe_values_callback_poll,
            unsubscribe: boltffi_event_bus_subscribe_values_callback_unsubscribe,
            freeFn: boltffi_event_bus_subscribe_values_callback_free,
            atomicCas: boltffi_atomic_u8_cas,
            callback: callback
        )
        context.start()
        return EventBusSubscribeValuesCallbackCancellable { context.requestTermination() }
    }
}

public final class EventBusSubscribeValuesBatchSubscription {
    private let handle: SubscriptionHandle?
    private let readBatchFn: (SubscriptionHandle, UInt) -> [Int32]
    private let waitFn: (SubscriptionHandle, UInt32) -> Int32
    private let unsubscribeFn: (SubscriptionHandle?) -> Void
    private let freeFn: (SubscriptionHandle?) -> Void
    private var isUnsubscribed = false

    init(
        handle: SubscriptionHandle?,
        readBatch: @escaping (SubscriptionHandle, UInt) -> [Int32],
        wait: @escaping (SubscriptionHandle, UInt32) -> Int32,
        unsubscribe: @escaping (SubscriptionHandle?) -> Void,
        freeFn: @escaping (SubscriptionHandle?) -> Void
    ) {
        self.handle = handle
        self.readBatchFn = readBatch
        self.waitFn = wait
        self.unsubscribeFn = unsubscribe
        self.freeFn = freeFn
    }

    deinit {
        freeFn(handle)
    }

    public func popBatch(maxCount: UInt = 16) -> [Int32] {
        guard let h = handle else { return [] }
        return readBatchFn(h, maxCount)
    }

    public func wait(timeout: UInt32) -> Int32 {
        guard let h = handle else { return -1 }
        return waitFn(h, timeout)
    }

    public func unsubscribe() {
        guard !isUnsubscribed else { return }
        isUnsubscribed = true
        unsubscribeFn(handle)
    }
}

